function renderColumnChart(n,t){function h(){const t="0123456789ABCDEF";let n="#";for(let i=0;i<6;i++)n+=t[Math.floor(Math.random()*16)];return n}const f=Array.from(new Set(n.flatMap(n=>Object.keys(n.departmentsOrders)))),e=n.map(n=>new Date(n.date).toISOString()).sort(),o=t<=30,i={Electroplating:"#c0c0c0",Embroidery:"#ffbc00",Engraving:"#727cf5",Metal:"#0acf97",UVP:"#FA5C7C",Unknown:"#6c757d",Plants:"#3cb371",Sublimation:"#b0c4de",Wood:"#ffe4c4",Fulfillment:"#ee82ee"},r=f.map(t=>{const r=n.map(n=>n.departmentsOrders[t]||0);return{name:t,data:r,color:i[t]||h()}}),s=n.map(n=>Object.values(n.departmentsOrders).reduce((n,t)=>n+t));const l=r.map(n=>i[n.name]),c={series:r,chart:{type:"bar",toolbar:{show:!0,tools:{download:!0,selection:!1,zoom:!1,zoomin:!1,zoomout:!1,pan:!1,reset:!1},"export":{svg:{filename:"historical_trends_chart"},png:{filename:"historical_trends_chart"}}},height:350,stacked:!0},plotOptions:{bar:{horizontal:!1}},xaxis:{type:"datetime",categories:e},yaxis:{title:{text:"Number of Orders"}},legend:{position:"top",horizontalAlign:"left"},tooltip:{y:{formatter:function(t,{seriesIndex:r,dataPointIndex:i,w:u}){const f=u.config.series[r].name,e=u.config.series[r].data[i],o=n[i].departmentsProductProfit[f]||0;return"Orders: "+e+"<br>"+f+":  $"+o.toFixed(2)},title:{formatter:function(){return""}}},x:{show:!0,formatter:function(n,{dataPointIndex:t}){const r=s[t],i=new Date(n),u=i.getDate(),f=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"][i.getMonth()],e=`${u} ${f}`;return e+" - Total Orders: "+r}}},dataLabels:{enabled:o},responsive:[{breakpoint:1500,options:{dataLabels:{enabled:!1}}},]},u=new ApexCharts(document.querySelector("#column-chart-historical-trends"),c);u.render().then(()=>{isTrendsInitialized||(u.updateOptions({}),isTrendsInitialized=!0)})}